// login.controller.test.ts
import request from 'supertest';
import express from 'express';
import { loginRouter } from './login.controller';

const app = express();
app.use(express.json());
app.use('/login', loginRouter);

describe('POST /login', () => {
  test('Renvoie un token si les identifiants sont valides', async () => {
    const res = await request(app)
      .post('/login')
      .send({ email: 'test@example.com', password: 'password123' });

    expect(res.status).toBe(200);
    expect(res.body.token).toBeDefined();
  });

  test('Renvoie une erreur si le mot de passe est incorrect', async () => {
    const res = await request(app)
      .post('/login')
      .send({ email: 'test@example.com', password: 'wrongpassword' });

    expect(res.status).toBe(401);
    expect(res.body.error).toBe('Email ou mot de passe incorrect');
  });
});
```

---

### **Failles de sécurité à éviter**

1. **Stockage du mot de passe en clair**  
   Si l'utilisateur n'est pas stocké avec un hash bcrypt, cela expose les mots de passe en cas de fuite.

2. **Utilisation de `process.env.JWT_SECRET` sans vérification**  
   Si la variable d'environnement n'est pas définie, le JWT ne sera pas signé correctement et peut être falsifié.

3. **Absence de protection contre les attaques de type brute-force**  
   Aucune limite de tentatives ou de délai entre les connexions échouées n’est implémentée, ce qui rend l’endpoint vulnérable aux attaques de force brute.

---

> ✅ *Remarque : Pour une implémentation sécurisée, assurez-vous que toutes les données sensibles sont correctement protégées, et que les secrets sont gérés via un système de gestion de secrets (ex: AWS Secrets Manager, Vault, etc).*

