type Item = {
    price: number;
};

type Cart = {
    items: Item[];
    tax: number;
};

function calculateTotal(cart: Cart): number {
    if (cart.items.length === 0) {
        throw new Error("Le panier est vide.");
    }
    if (cart.tax < 0) {
        throw new Error("La taxe ne peut pas être négative.");
    }

    const total = cart.items.reduce((accumulator, item) => {
        if (item.price === undefined || item.price === null) {
            throw new Error("Un article n'a pas de prix défini.");
        }
        return accumulator + item.price * cart.tax;
    }, 0);

    return total;
}

// Cas de test 1: Panier avec des items et une taxe valide
